CREATE OR REPLACE FUNCTION fpb_get_loan_coll_dec (as_conno char,ai_num integer , as_detail char) RETURNS char AS $body$
DECLARE

 ls_coll_desc varchar(200);
  ls_member_name varchar(100);
  ls_member_no varchar(12);

  cur_data CURSOR FOR
--  select collateral_type_code,ref_own_no,collateral_description
--  from sc_lon_m_contract_coll
--  where(loan_contract_no = as_conno) 
--  and(collateral_no = ai_num)
--  order by collateral_no ;
    SELECT tab.*
    from (
        SELECT ROW_NUMBER() OVER (ORDER BY collateral_no) AS run_number
        ,collateral_type_code
        ,ref_own_no
        ,collateral_description
        from sc_lon_m_contract_coll
        where (loan_contract_no = as_conno) 
        order by collateral_no 
        ) tab 
        where tab.run_number = ai_num;
  type tabrowi_coll is table of cur_data%rowtype index by integer;ltabrowi_coll tabrowi_coll;


BEGIN
  open cur_data;fetch cur_data bulk collect into ltabrowi_coll limit 10;close cur_data;
  if ltabrowi_coll.count <> 1 then
    return null;
  end if;

  case ltabrowi_coll[1].collateral_type_code
  when '01' then
    if as_detail = 'mem_no' then
        ls_member_no :=  trim(both ltabrowi_coll[1].ref_own_no);
        ls_coll_desc := ls_member_no;
    elsif as_detail = 'mem_name' then
        ls_member_name := trim(both pka_com_function.fp_get_member_name(ltabrowi_coll[1].ref_own_no));
        ls_coll_desc := ls_member_name;
    end if;
  when '02' then

    if as_detail = 'mem_no' then
        ls_member_no :=  trim(both ltabrowi_coll[1].ref_own_no);
        ls_coll_desc := ls_member_no;
    elsif as_detail = 'mem_name' then
        ls_coll_desc := 'หุ้นค้ำประกัน';
    end if;
  when '03' then
    ls_coll_desc := 'เงินฝากค้ำประกัน '||trim(both ltabrowi_coll[1].ref_own_no);
  when '04' then
    if as_detail = 'mem_no' then
        ls_coll_desc := '';
    elsif as_detail = 'mem_name' then
        ls_coll_desc := trim(both ltabrowi_coll[1].collateral_description);
    end if;
  else
    ls_coll_desc := trim(both ltabrowi_coll[1].collateral_description);
  end case;
  return ls_coll_desc;
exception when others then CALL spa_dberror('FPB_GET_LOAN_COLL_DEC');
end;
$body$
LANGUAGE PLPGSQL
SECURITY DEFINER
;
